import React, { useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Page } from '../components/Layout';
import { CARS } from '../mockCars';
import { createBooking, getId, getRole, isLoggedIn } from '../services/authService';

export default function CarDetailPage() {
  const navigate = useNavigate();
  const { id } = useParams();
  const car = useMemo(
    () => CARS.find((item) => String(item.id) === String(id)) || CARS[0],
    [id]
  );
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const totalDays = useMemo(() => {
    if (!fromDate || !toDate) return 0;
    const from = new Date(fromDate);
    const to = new Date(toDate);
    return Math.ceil((to - from) / (1000 * 60 * 60 * 24));
  }, [fromDate, toDate]);

  const totalPrice = totalDays > 0 ? totalDays * car.rentPerDay : 0;

  const handleBooking = async () => {
    setError('');

    if (!isLoggedIn()) {
      navigate('/login');
      return;
    }

    if (getRole() !== 'CUSTOMER') {
      setError('Please login as a customer to book a car.');
      return;
    }

    if (!fromDate || !toDate || totalDays <= 0) {
      setError('Please select valid booking dates.');
      return;
    }

    setLoading(true);
    try {
      const data = await createBooking({
        customerId: Number(getId()),
        variantId: Number(car.id),
        carName: car.name,
        carImage: car.image,
        fromDate,
        toDate,
        totalDays,
        totalPrice
      });

      if (!data.success) {
        setError(data.message || 'Booking request failed.');
        setLoading(false);
        return;
      }

      window.alert('Booking initiated successfully! Your request is pending admin approval.');
      navigate('/customer/bookings');
    } catch (err) {
      setError(err?.response?.data?.message || 'Booking request failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Page title={car.name} subtitle={`${car.company} • ${car.modelNumber} • ${car.year}`}>
      <section className="grid detailGrid">
        <div className="card">
          <img src={car.image} alt={car.name} className="detailImage" />
          <h3>Overview</h3>
          <p>{car.description}</p>
          <div className="featureList">
            {car.features.map((feature) => (
              <span className="pill" key={feature}>{feature}</span>
            ))}
          </div>
        </div>
        <div className="card">
          {error && <div className="alert error">{error}</div>}
          <div className="price">₹{car.rentPerDay.toLocaleString()} <span>/ day</span></div>
          <label>
            From date
            <input type="date" value={fromDate} onChange={(e) => setFromDate(e.target.value)} />
          </label>
          <label>
            To date
            <input type="date" value={toDate} onChange={(e) => setToDate(e.target.value)} />
          </label>
          <div className="summary">
            <div><span>Total days</span><strong>{totalDays > 0 ? totalDays : '-'}</strong></div>
            <div><span>Total amount</span><strong>₹{totalPrice.toLocaleString()}</strong></div>
          </div>
          <button className="button" disabled={loading} onClick={handleBooking}>
            {loading ? 'Booking...' : 'Book Car'}
          </button>
        </div>
      </section>
    </Page>
  );
}
